from __future__ import annotations

import os
import random
from typing import Callable, Dict, List, Optional, Sequence, Tuple

import cv2
import numpy as np
from PIL import Image
from torch.utils.data import Dataset

from third_parties.CrossOver.render_utils import (
    crop_image,
    load_and_center_mesh,
    render_pointcloud_density,
    render_scene,
    resize_with_padding,
)
from aria_mmfe.code_snippets.plotters import orthographic_project_points


class ScannetDataset(Dataset):
    """
    PyTorch Dataset that renders ScanNet modalities on-the-fly.

    Each sample yields a floorplan rendered from `floor+obj.ply` and a density_map
    generated by projecting the point cloud stored in `data3D.npz`.
    """

    def __init__(
        self,
        root_dir: str,
        scene_ids: Optional[Sequence[str]] = None,
        scene_ids_file: Optional[str] = None,
        image_size: Optional[Tuple[int, int]] = None,
        dual_transform: Optional[Callable] = None,
        modality_pairs: Optional[List[Tuple[str, str]]] = None,
        generate: bool = False,
        resolution: int = 1024,
        padding: int = 50,
        point_axis: str = "z",
        point_size: int = 1,
        crop_pad: int = 0,
    ) -> None:
        super().__init__()

        if not os.path.isabs(root_dir):
            root_dir = os.path.abspath(root_dir)

        self.root_dir: str = root_dir
        self.image_size: Optional[Tuple[int, int]] = tuple(image_size) if image_size else None
        self.dual_transform = dual_transform
        self.generate = bool(generate)
        self.render_resolution: int = int(resolution)
        self.render_padding: int = max(0, int(padding))
        self.inner_resolution: int = self.render_resolution - (2 * self.render_padding)
        if self.inner_resolution <= 0:
            raise ValueError("resolution must be larger than twice the padding.")

        self.point_axis = point_axis
        self.point_size = max(1, int(point_size))
        self.point_size_large = max(1, self.point_size * 4)
        self.crop_pad = max(0, int(crop_pad))

        self.floorplan_pattern = "scene_{scene_id}_floorplan.png"
        self.density_pattern = "scene_{scene_id}_density.png"
        self.density_large_pattern = "scene_{scene_id}_density_large.png"
        self.density_mesh_pattern = "scene_{scene_id}_density_mesh.png"
        self.density_mesh_noisy_pattern = "scene_{scene_id}_density_mesh_noisy.png"

        self.modalities = ["floorplan", "density_map", "density_map_point4", "density_map_mesh", "density_map_mesh_noisy"]
        if modality_pairs is None:
            # Exclude pairs where both density_map and density_map_point4 appear together
            # Also exclude pairs where both density_map_mesh and density_map_mesh_noisy appear together
            excluded_pairs = [
                {"density_map", "density_map_point4"},
                {"density_map_mesh", "density_map_mesh_noisy"},
            ]
            self.modality_pairs = [
                (m0, m1) 
                for m0 in self.modalities 
                for m1 in self.modalities 
                if m0 != m1 
                and not any({m0, m1} == excluded_pair for excluded_pair in excluded_pairs)
            ]
        else:
            self.modality_pairs = modality_pairs

        if scene_ids_file is not None:
            scene_ids = self._load_ids_from_file(scene_ids_file)
        if scene_ids is None:
            scene_ids = self._discover_scene_ids()

        self.scene_ids: List[str] = list(scene_ids)
        if not self.scene_ids:
            raise RuntimeError(f"No valid ScanNet scenes found under {self.root_dir}")

    # ------------------------------------------------------------------
    # Scene discovery / book-keeping
    # ------------------------------------------------------------------
    def _discover_scene_ids(self) -> List[str]:
        scene_ids: List[str] = []
        if not os.path.isdir(self.root_dir):
            return scene_ids

        for entry in sorted(os.listdir(self.root_dir)):
            full_path = os.path.join(self.root_dir, entry)
            if not os.path.isdir(full_path):
                continue

            if self.generate:
                mesh_path = os.path.join(full_path, "floor+obj.ply")
                npz_path = os.path.join(full_path, "data3D.npz")
                if os.path.exists(mesh_path) and os.path.exists(npz_path):
                    scene_ids.append(entry)
            else:
                if (
                    os.path.exists(self._modality_filepath(entry, "floorplan"))
                    and os.path.exists(self._modality_filepath(entry, "density_map"))
                    and os.path.exists(self._modality_filepath(entry, "density_map_point4"))
                    and os.path.exists(self._modality_filepath(entry, "density_map_mesh"))
                    and os.path.exists(self._modality_filepath(entry, "density_map_mesh_noisy"))
                ):
                    scene_ids.append(entry)
        return scene_ids

    def _load_ids_from_file(self, ids_file: str) -> List[str]:
        if not os.path.exists(ids_file):
            raise FileNotFoundError(f"Scene IDs file not found: {ids_file}")

        ids: List[str] = []
        with open(ids_file, "r", encoding="utf-8") as handle:
            for raw_line in handle:
                line = raw_line.strip()
                if line and not line.startswith("#"):
                    ids.append(line)

        ids = sorted(set(ids))

        valid_ids: List[str] = []
        for sid in ids:
            scene_dir = os.path.join(self.root_dir, sid)
            if self.generate:
                mesh_path = os.path.join(scene_dir, "floor+obj.ply")
                npz_path = os.path.join(scene_dir, "data3D.npz")
                if os.path.exists(mesh_path) and os.path.exists(npz_path):
                    valid_ids.append(sid)
            else:
                if (
                    os.path.exists(self._modality_filepath(sid, "floorplan"))
                    and os.path.exists(self._modality_filepath(sid, "density_map"))
                    and os.path.exists(self._modality_filepath(sid, "density_map_point4"))
                    and os.path.exists(self._modality_filepath(sid, "density_map_mesh"))
                    and os.path.exists(self._modality_filepath(sid, "density_map_mesh_noisy"))
                ):
                    valid_ids.append(sid)

        if not valid_ids:
            raise RuntimeError(f"No valid scene IDs from {ids_file}")
        return valid_ids

    def __len__(self) -> int:
        return len(self.scene_ids)

    # ------------------------------------------------------------------
    # Rendering helpers
    # ------------------------------------------------------------------
    def _get_scene_paths(self, scene_id: str) -> Dict[str, str]:
        scene_dir = os.path.join(self.root_dir, scene_id)
        mesh_path = os.path.join(scene_dir, "floor+obj.ply")
        npz_path = os.path.join(scene_dir, "data3D.npz")
        if self.generate:
            if not os.path.exists(mesh_path):
                raise FileNotFoundError(f"Missing mesh for {scene_id}: {mesh_path}")
            if not os.path.exists(npz_path):
                raise FileNotFoundError(f"Missing data3D.npz for {scene_id}: {npz_path}")
        return {"scene_dir": scene_dir, "mesh_path": mesh_path, "npz_path": npz_path}

    @staticmethod
    def _ensure_uint8(image: np.ndarray) -> np.ndarray:
        if image.dtype == np.uint8:
            return image
        img = image.astype(np.float32)
        if img.max() <= 1.0:
            img *= 255.0
        img = np.clip(img, 0, 255)
        return img.astype(np.uint8)


    def _render_floorplan(self, scene_id: str) -> np.ndarray:
        paths = self._get_scene_paths(scene_id)
        rendered = render_scene(paths["mesh_path"])
        rendered = crop_image(np.array(rendered), pad=self.crop_pad)
        rendered = resize_with_padding(rendered, self.render_resolution, self.render_padding)
        return self._ensure_uint8(rendered)

    def _load_pointcloud(self, npz_path: str) -> np.ndarray:
        with np.load(npz_path, allow_pickle=True) as data:
            if "scene" not in data:
                raise KeyError(f"'scene' entry missing in {npz_path}")
            scene_entry = data["scene"].item()
        coords = scene_entry.get("pcl_coords")
        if coords is None:
            raise KeyError(f"'pcl_coords' missing in {npz_path}")
        return np.asarray(coords, dtype=np.float32)

    def _render_density_map(self, scene_id: str, point_size: Optional[int] = None) -> np.ndarray:
        paths = self._get_scene_paths(scene_id)
        coords = self._load_pointcloud(paths["npz_path"])
        chosen_point_size = point_size if point_size is not None else self.point_size
        density = render_pointcloud_density(
            coords,
            axis=self.point_axis,
            resolution=self.render_resolution,
            padding=self.render_padding,
            point_size=chosen_point_size,
        )
        return self._ensure_uint8(density)

    def _render_density_map_large(self, scene_id: str) -> np.ndarray:
        return self._render_density_map(scene_id, point_size=self.point_size_large)

    def _render_density_map_mesh(self, scene_id: str) -> np.ndarray:
        """Render density map from points sampled from the mesh surface."""
        paths = self._get_scene_paths(scene_id)
        mesh = load_and_center_mesh(paths["mesh_path"])
        
        # Sample points from mesh - use similar number as original point cloud
        coords = self._load_pointcloud(paths["npz_path"])
        num_samples = min(50000, len(coords))
        mesh_points = mesh.sample(num_samples)
        
        density = render_pointcloud_density(
            mesh_points,
            axis=self.point_axis,
            resolution=self.render_resolution,
            padding=self.render_padding,
            point_size=self.point_size,
            rotate=False,
        )
        return self._ensure_uint8(density)

    def _render_density_map_mesh_noisy(self, scene_id: str) -> np.ndarray:
        """Render density map from mesh points with non-uniform noise added based on 2D position."""
        paths = self._get_scene_paths(scene_id)
        mesh = load_and_center_mesh(paths["mesh_path"])
        
        # Sample points from mesh - use similar number as original point cloud
        coords = self._load_pointcloud(paths["npz_path"])
        num_samples = min(50000, len(coords))
        mesh_points = mesh.sample(num_samples)
        
        # Project points to 2D to determine noise magnitude per point
        # Use the same rotation as render_pointcloud_density (rotate=False means no rotation)
        proj_2d, _ = orthographic_project_points(mesh_points, axis=self.point_axis)
        
        # Compute bounding box for noise field
        x_2d = proj_2d[:, 0]
        y_2d = proj_2d[:, 1]
        x_min, x_max = x_2d.min(), x_2d.max()
        y_min, y_max = y_2d.min(), y_2d.max()
        w_true = x_max - x_min
        h_true = y_max - y_min
        
        # Create spatially-varying noise field
        noise_resolution = 256
        noise_x_field = np.random.randn(noise_resolution, noise_resolution).astype(np.float32)
        noise_y_field = np.random.randn(noise_resolution, noise_resolution).astype(np.float32)
        
        # Apply Gaussian blur for smooth spatial variation
        sigma = noise_resolution * 0.15
        noise_x_field = cv2.GaussianBlur(noise_x_field, (0, 0), sigmaX=sigma, sigmaY=sigma)
        noise_y_field = cv2.GaussianBlur(noise_y_field, (0, 0), sigmaX=sigma, sigmaY=sigma)
        
        # Normalize to [0, 1] range
        noise_x_field = (noise_x_field - noise_x_field.min()) / (noise_x_field.max() - noise_x_field.min() + 1e-9)
        noise_y_field = (noise_y_field - noise_y_field.min()) / (noise_y_field.max() - noise_y_field.min() + 1e-9)
        
        # Map 2D points to noise field coordinates
        x_idx = np.clip(((x_2d - x_min) / (w_true + 1e-9) * (noise_resolution - 1)).astype(np.int32), 0, noise_resolution - 1)
        y_idx = np.clip(((y_2d - y_min) / (h_true + 1e-9) * (noise_resolution - 1)).astype(np.int32), 0, noise_resolution - 1)
        
        # Sample noise magnitude from field (0 to max_noise)
        max_noise = 0.02 * max(w_true, h_true)  # 2% of larger dimension
        noise_magnitude_x = noise_x_field[y_idx, x_idx] * max_noise
        noise_magnitude_y = noise_y_field[y_idx, x_idx] * max_noise
        
        # Generate random noise direction and scale by magnitude
        noise_dirs = np.random.randn(len(mesh_points), 2).astype(np.float32)
        noise_dirs = noise_dirs / (np.linalg.norm(noise_dirs, axis=1, keepdims=True) + 1e-9)
        noise_2d = noise_dirs * np.stack([noise_magnitude_x, noise_magnitude_y], axis=1)
        
        # Add noise to mesh points in the XY plane (before projection)
        # We need to add noise in the plane perpendicular to the projection axis
        noisy_points = mesh_points.copy()
        if self.point_axis == "z":
            # Add noise in XY plane
            noisy_points[:, 0] += noise_2d[:, 0]
            noisy_points[:, 1] += noise_2d[:, 1]
        elif self.point_axis == "y":
            # Add noise in XZ plane
            noisy_points[:, 0] += noise_2d[:, 0]
            noisy_points[:, 2] += noise_2d[:, 1]
        else:  # axis == "x"
            # Add noise in YZ plane
            noisy_points[:, 1] += noise_2d[:, 0]
            noisy_points[:, 2] += noise_2d[:, 1]
        
        # Render with noisy points
        density = render_pointcloud_density(
            noisy_points,
            axis=self.point_axis,
            resolution=self.render_resolution,
            padding=self.render_padding,
            point_size=self.point_size,
            rotate=False,
        )
        return self._ensure_uint8(density)

    def _modality_filepath(self, scene_id: str, modality: str, root_dir: str = None) -> str:
        scene_dir = os.path.join(root_dir if root_dir is not None else self.root_dir, scene_id)
        if modality == "floorplan":
            filename = self.floorplan_pattern.format(scene_id=scene_id)
        elif modality == "density_map":
            filename = self.density_pattern.format(scene_id=scene_id)
        elif modality == "density_map_point4":
            filename = self.density_large_pattern.format(scene_id=scene_id)
        elif modality == "density_map_mesh":
            filename = self.density_mesh_pattern.format(scene_id=scene_id)
        elif modality == "density_map_mesh_noisy":
            filename = self.density_mesh_noisy_pattern.format(scene_id=scene_id)
        else:
            raise ValueError(f"Unknown modality '{modality}'")
        return os.path.join(scene_dir, filename)

    def _load_floorplan_from_image(self, scene_id: str) -> np.ndarray:
        image_path = self._modality_filepath(scene_id, "floorplan")
        image = cv2.imread(image_path, cv2.IMREAD_COLOR)
        if image is None:
            raise FileNotFoundError(f"Failed to load floorplan image: {image_path}")
        image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        # If image size doesn't match, resize with padding
        if image.shape[:2] != (self.render_resolution, self.render_resolution):
            image = resize_with_padding(image, self.render_resolution, self.render_padding)
        return self._ensure_uint8(image)

    def _load_density_from_image(self, scene_id: str, modality_key: str) -> np.ndarray:
        image_path = self._modality_filepath(scene_id, modality_key)
        image = cv2.imread(image_path, cv2.IMREAD_COLOR)
        if image is None:
            raise FileNotFoundError(f"Failed to load image: {image_path}")
        image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        # If image size doesn't match, resize with padding
        if image.shape[:2] != (self.render_resolution, self.render_resolution):
            image = resize_with_padding(image, self.render_resolution, self.render_padding)
        return self._ensure_uint8(image)

    def _load_modality(self, scene_id: str, modality_type: str) -> np.ndarray:
        if modality_type == "floorplan":
            return self._render_floorplan(scene_id) if self.generate else self._load_floorplan_from_image(scene_id)
        if modality_type == "density_map":
            return self._render_density_map(scene_id) if self.generate else self._load_density_from_image(scene_id, "density_map")
        if modality_type == "density_map_point4":
            if self.generate:
                return self._render_density_map_large(scene_id)
            return self._load_density_from_image(scene_id, "density_map_point4")
        if modality_type == "density_map_mesh":
            if self.generate:
                return self._render_density_map_mesh(scene_id)
            return self._load_density_from_image(scene_id, "density_map_mesh")
        if modality_type == "density_map_mesh_noisy":
            if self.generate:
                return self._render_density_map_mesh_noisy(scene_id)
            return self._load_density_from_image(scene_id, "density_map_mesh_noisy")
        raise ValueError(f"Unknown modality '{modality_type}'")

    # ------------------------------------------------------------------
    # Dataset API
    # ------------------------------------------------------------------
    def _apply_dual_transform(self, img0: np.ndarray, img1: np.ndarray) -> Tuple[np.ndarray, np.ndarray]:
        if self.dual_transform is None:
            return img0, img1

        transform = self.dual_transform
        if callable(transform):
            return transform(img0, img1)

        result0, result1 = img0, img1
        for t in transform:
            result0, result1 = t(result0, result1)
        return result0, result1

    @staticmethod
    def _resize_numpy(image_np: np.ndarray, size_hw: Tuple[int, int]) -> np.ndarray:
        pil_img = Image.fromarray(image_np)
        height, width = int(size_hw[0]), int(size_hw[1])
        pil_img = pil_img.resize((width, height), resample=Image.BILINEAR)
        return np.array(pil_img)

    def __getitem__(self, index: int) -> Dict[str, np.ndarray]:
        scene_id = self.scene_ids[index]
        paths = self._get_scene_paths(scene_id)

        m0_type, m1_type = random.choice(self.modality_pairs)

        m0_image = self._load_modality(scene_id, m0_type)
        m1_image = self._load_modality(scene_id, m1_type)

        if self.image_size is not None:
            m0_image = self._resize_numpy(m0_image, self.image_size)
            m1_image = self._resize_numpy(m1_image, self.image_size)

        m0_image, m1_image = self._apply_dual_transform(m0_image, m1_image)

        return {
            "modality_0": m0_image,
            "modality_1": m1_image,
            "m0_type": m0_type,
            "m1_type": m1_type,
            "sample_id": scene_id,
            "sample_dir": paths["scene_dir"],
        }

    # ------------------------------------------------------------------
    # Utility helpers for preprocessing scripts
    # ------------------------------------------------------------------
    def generate_and_save(self, index: int, furniture_pct: Optional[float] = None) -> Dict[str, str]:
        """
        Convenience helper that renders both modalities and saves them as PNGs.
        The `furniture_pct` argument is kept for backward compatibility but ignored.
        """
        scene_id = self.scene_ids[index]
        parent_dir = os.path.dirname(self.root_dir)
        scene_dir = os.path.join(parent_dir, "rendered", scene_id)
        os.makedirs(scene_dir, exist_ok=True)

        floorplan = self._render_floorplan(scene_id)
        density = self._render_density_map(scene_id)
        density_large = self._render_density_map_large(scene_id)
        density_mesh = self._render_density_map_mesh(scene_id)
        density_mesh_noisy = self._render_density_map_mesh_noisy(scene_id)

        floorplan_path = self._modality_filepath(scene_id, "floorplan", os.path.dirname(scene_dir))
        density_path = self._modality_filepath(scene_id, "density_map", os.path.dirname(scene_dir))
        density_large_path = self._modality_filepath(scene_id, "density_map_point4", os.path.dirname(scene_dir))
        density_mesh_path = self._modality_filepath(scene_id, "density_map_mesh", os.path.dirname(scene_dir))
        density_mesh_noisy_path = self._modality_filepath(scene_id, "density_map_mesh_noisy", os.path.dirname(scene_dir))

        cv2.imwrite(floorplan_path, cv2.cvtColor(floorplan, cv2.COLOR_RGB2BGR))
        cv2.imwrite(density_path, cv2.cvtColor(density, cv2.COLOR_RGB2BGR))
        cv2.imwrite(density_large_path, cv2.cvtColor(density_large, cv2.COLOR_RGB2BGR))
        cv2.imwrite(density_mesh_path, cv2.cvtColor(density_mesh, cv2.COLOR_RGB2BGR))
        cv2.imwrite(density_mesh_noisy_path, cv2.cvtColor(density_mesh_noisy, cv2.COLOR_RGB2BGR))

        return {
            "scene_id": scene_id,
            "floorplan_path": floorplan_path,
            "density_map_path": density_path,
            "density_map_point4_path": density_large_path,
            "density_map_mesh_path": density_mesh_path,
            "density_map_mesh_noisy_path": density_mesh_noisy_path,
            "scene_dir": scene_dir,
        }

    def get_all_sample_modalities(self, index: int) -> Dict[str, Dict[str, np.ndarray]]:
        """
        Load all modalities for a scene.
        Returns: {"floorplan": {"0": image}, "density_map": {"0": image}}
        """
        scene_id = self.scene_ids[index]
        modalities: Dict[str, Dict[str, np.ndarray]] = {}
        for modality in self.modalities:
            try:
                img = self._load_modality(scene_id, modality)
            except Exception as exc:  # pragma: no cover - only for logging
                print(f"Warning: Failed to load {modality} for {scene_id}: {exc}")
                continue
            modalities.setdefault(modality, {})["0"] = img
        return modalities


